import React, { useState } from 'react';
import IndividualAnalysis from './IndividualAnalysis';
import BatchAnalysis from './BatchAnalysis';
import './App.css';

function App() {
  const [customerData, setCustomerData] = useState({});
  const [results, setResults] = useState(null);
  const [loading, setLoading] = useState(false);

  const [selectedFile, setSelectedFile] = useState(null);
  const [batchResults, setBatchResults] = useState(null);
  const [batchLoading, setBatchLoading] = useState(false);

  const [currentView, setCurrentView] = useState('individual');
  const [sidebarOpen, setSidebarOpen] = useState(false); // Default closed

  const handleInputChange = (newData) => {
    setCustomerData(newData);
  };

  const handleAnalyze = async () => {
    setLoading(true);
    // Simulate API call
    setTimeout(() => {
      setResults({
        probability: 0.75,
        prediction: true,
        feature_importance: {
          Tenure: 0.3,
          SatisfactionScore: 0.25,
          OrderCount: 0.2,
          CashbackAmount: 0.15,
          DaySinceLastOrder: 0.1
        }
      });
      setLoading(false);
    }, 2000);
  };

  const handleReset = () => {
    setCustomerData({});
    setResults(null);
  };

  const handleFileChange = (e) => {
    const file = e.target.files[0];
    setSelectedFile(file);
  };

  const handleBatchAnalyze = async () => {
    setBatchLoading(true);
    // Simulate batch processing
    setTimeout(() => {
      setBatchResults({
        total_records: 1500,
        churn_count: 345,
        churn_rate: 0.23,
        download_url: '#'
      });
      setBatchLoading(false);
    }, 3000);
  };

  const toggleSidebar = () => {
    setSidebarOpen(!sidebarOpen);
  };

  return (
    <div className="app">
      {/* Header */}
      <div className="app-header">
        <div className="header-left">
          <div className="logo-title-container">
            <div className="app-logo">
              <div className="logo-placeholder">
                <span className="logo-text">PCA</span>
              </div>
            </div>
            <div className="title-container">
              <h1 className="app-title">E-commerce ChurnGuard</h1>
              <p className="session-title">Customer Churn Prediction Analytics</p>
            </div>
          </div>
        </div>
        <div className="header-right">
          <div className="header-stats">
            <div className="stat-item">
              <span className="stat-label">Overall Churn Rate</span>
              <span className="stat-value">23%</span>
            </div>
            <div className="stat-item">
              <span className="stat-label">Active Customers</span>
              <span className="stat-value">1,247</span>
            </div>
            <div className="stat-item">
              <span className="stat-label">At Risk</span>
              <span className="stat-value warning">287</span>
            </div>
          </div>
        </div>
      </div>

      <div className="main-layout">
        {/* Sidebar */}
        <div className={`sidebar ${sidebarOpen ? 'open' : 'closed'}`}>
          <nav className="sidebar-nav">
            {/* Toggle Button inside Nav Bar */}
            <div className="nav-toggle-section">
              <button 
                className="nav-toggle-btn"
                onClick={toggleSidebar}
              >
                <span className="nav-toggle-icon">
                  {sidebarOpen ? '◀' : '▶'}
                </span>
                {sidebarOpen && <span className="nav-toggle-text">Collapse Menu</span>}
              </button>
            </div>

            <div className="nav-section">
              <div className="nav-section-label">ANALYSIS</div>
              <button 
                className={`nav-item ${currentView === 'individual' ? 'active' : ''}`}
                onClick={() => setCurrentView('individual')}
              >
                <span className="nav-icon">👤</span>
                {sidebarOpen && <span className="nav-text">Individual Analysis</span>}
                {!sidebarOpen && <div className="nav-tooltip">Individual Analysis</div>}
              </button>
              <button 
                className={`nav-item ${currentView === 'batch' ? 'active' : ''}`}
                onClick={() => setCurrentView('batch')}
              >
                <span className="nav-icon">⚡</span>
                {sidebarOpen && <span className="nav-text">Batch Processing</span>}
                {!sidebarOpen && <div className="nav-tooltip">Batch Processing</div>}
              </button>
            </div>

            <div className="nav-section">
              <div className="nav-section-label">DASHBOARD</div>
              <button className="nav-item">
                <span className="nav-icon">📊</span>
                {sidebarOpen && <span className="nav-text">Overview</span>}
                {!sidebarOpen && <div className="nav-tooltip">Overview</div>}
              </button>
              <button className="nav-item">
                <span className="nav-icon">📈</span>
                {sidebarOpen && <span className="nav-text">Analytics</span>}
                {!sidebarOpen && <div className="nav-tooltip">Analytics</div>}
              </button>
              <button className="nav-item">
                <span className="nav-icon">🔔</span>
                {sidebarOpen && <span className="nav-text">Alerts</span>}
                {!sidebarOpen && <div className="nav-tooltip">Alerts</div>}
              </button>
            </div>

            <div className="nav-section">
              <div className="nav-section-label">SETTINGS</div>
              <button className="nav-item">
                <span className="nav-icon">⚙️</span>
                {sidebarOpen && <span className="nav-text">Settings</span>}
                {!sidebarOpen && <div className="nav-tooltip">Settings</div>}
              </button>
              <button className="nav-item">
                <span className="nav-icon">👤</span>
                {sidebarOpen && <span className="nav-text">Profile</span>}
                {!sidebarOpen && <div className="nav-tooltip">Profile</div>}
              </button>
            </div>
          </nav>
        </div>

        {/* Main Content */}
        <div className={`content-area ${!sidebarOpen ? 'expanded' : ''}`}>
          {/* View Title Display */}
          <div className="view-title-section">
            <div className="view-header">
              <h2 className="view-title">
                {currentView === 'individual' ? (
                  <>
                    <span className="view-icon">👤</span>
                    Individual Customer Analysis
                  </>
                ) : (
                  <>
                    <span className="view-icon">⚡</span>
                    Batch Processing
                  </>
                )}
              </h2>
              <div className="view-actions">
                <button className="action-btn primary">
                  <span className="btn-icon">📥</span>
                  Export Report
                </button>
                <button className="action-btn secondary">
                  <span className="btn-icon">🔄</span>
                  Refresh
                </button>
              </div>
            </div>
            <p className="view-subtitle">
              {currentView === 'individual' 
                ? "Analyze individual customer data to predict churn probability and identify key risk factors"
                : "Upload and process customer data in bulk to identify churn patterns across your customer base"
              }
            </p>
          </div>

          {/* Render Individual Analysis or Batch Analysis based on current view */}
          {currentView === 'individual' ? (
            <IndividualAnalysis
              customerData={customerData}
              onInputChange={handleInputChange}
              onAnalyze={handleAnalyze}
              onReset={handleReset}
              loading={loading}
              results={results}
            />
          ) : (
            <BatchAnalysis
              onFileChange={handleFileChange}
              onAnalyze={handleBatchAnalyze}
              loading={batchLoading}
              results={batchResults}
              selectedFile={selectedFile}
            />
          )}
        </div>
      </div>
    </div>
  );
}

export default App;
